class SegmentTree:
    def __init__(self, arr):
        self.n = len(arr)
        self.tree = [0] * (4 * self.n)
        self.arr = arr

        if self.n > 0:
            self._build(0, 0, self.n - 1)

    def _build(self, node, start, end):
        if start == end:
            self.tree[node] = self.arr[start]
            return

        mid = (start + end) // 2
        self._build(2 * node + 1, start, mid)
        self._build(2 * node + 2, mid + 1, end)
        self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]

    def update(self, idx, val):
        if not (0 <= idx < self.n):
            raise IndexError("Index out of bounds")
        self.arr[idx] = val
        self._update_tree(0, 0, self.n - 1, idx, val)

    def _update_tree(self, node, start, end, idx, val):
        if start == end:
            self.tree[node] = val
            return

        mid = (start + end) // 2
        if start <= idx <= mid:
            self._update_tree(2 * node + 1, start, mid, idx, val)
        else:
            self._update_tree(2 * node + 2, mid + 1, end, idx, val)
        self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2]

    def query(self, l, r):
        if not (0 <= l <= r < self.n):
            raise IndexError("Query range out of bounds")
        return self._query_tree(0, 0, self.n - 1, l, r)

    def _query_tree(self, node, start, end, l, r):
        if r < start or end < l:
            return 0

        if l <= start and end <= r:
            return self.tree[node]

        mid = (start + end) // 2
        p1 = self._query_tree(2 * node + 1, start, mid, l, r)
        p2 = self._query_tree(2 * node + 2, mid + 1, end, l, r)
        return p1 + p2
